  const ayahs: AyahProps[] = [
    { ayahId: 74, surahNumber: 2, pageNumber: 11, isComplete: true, continuesFromPrev: true, textData: "قَالُواْ ۶دْعُ لَنَا رَبَّژَ يُبَيِّن لَّنَا مَا هِيَؐ قَالَ إِنَّهُ„ يَقُولُ إِنَّهَا بَقَرَةٌ لاَّ فَارۣضٌ وَلاَ بِكْر٘ؐ عَوَانٛ بَيْنَ ذَ؛لِژَؐ فَافْعَلُواْ مَا تُومَرُونَؐ" },
    { ayahId: 75, surahNumber: 2, pageNumber: 11, isComplete: true, continuesFromPrev: false, textData: "قَالُواْ ۶دْعُ لَنَا رَبَّژَ يُبَيِّن لَّنَا مَا لَوْنُهَاؐ قَالَ إِنَّهُ„ يَقُولُ إِنَّهَا بَقَرَةٌ صَفْرَآءُ فَاقِعٌ لَّوْنُهَاؐ تَسُرُّ ۴لنَّــٰظِرۣينَؐ" },
    { ayahId: 76, surahNumber: 2, pageNumber: 11, isComplete: true, continuesFromPrev: false, textData: "قَالُواْ ۶دْعُ لَنَا رَبَّژَ يُبَيِّن لَّنَا مَا هِيَ إِنَّ ۰لْبَقَرَ تَشَــٰبَهَ عَلَيْنَا وَإِنَّآ إِن شَآءَ ۰للَّهُ لَمُهْتَدُونَؐ" },
    { ayahId: 77, surahNumber: 2, pageNumber: 11, isComplete: true, continuesFromPrev: false, textData: "قَالَ إِنَّهُ„ يَقُولُ إِنَّهَا بَقَرَةٌ لاَّ ذَلُولٌ تُثِيرُ ۴لاَرْضَ وَلاَ تَسْقِى ۱لْحَرْثثثَؐ مُسَلَّمَةٌ لاَّ شِيَةَ فِيهَاؐ قَالُواْ ۴چَـنَ جِيؔــتَ بِالْحَقﱢّؐ فَذَبَحُوهَا وَمَا كَادُواْ يَفْعَلُونَؐ" },
    { ayahId: 78, surahNumber: 2, pageNumber: 11, isComplete: true, continuesFromPrev: false, textData: "وَإِذْ قَتَلْتُمْ نَفْساً فَادَّ؛رَﹻتُمْ فِيهَاؐ وَاللَّهُ مُخْرۣجٌ مَّا كُنتُمْ تَكْتُمُونَؐ" },
    { ayahId: 79, surahNumber: 2, pageNumber: 11, isComplete: true, continuesFromPrev: false, textData: "فَقُلْنَا \"ضْرۣبُوهُ بِبَعْضِهَاؐ كَذَ؛لِژَ يُحْىِ ۱للَّهُ ۴لْمَوْتۭيٰ وَيُرۣيكُمُ; ءَايَــٰتِهِ” لَعَلَّكُمْ تَعْقِلُونَؐ" },
    { ayahId: 80, surahNumber: 2, pageNumber: 11, isComplete: true, continuesFromPrev: false, textData: "ثُمَّ قَسَــتْ قُلُوبُكُم مِّنۢ بَعْدِ ذَ؛لِژَ فَهِيَ كَالْحِجَارَةِ أَوَ اَشَدُّ قَسْوَةًؐ وَإِنَّ مِنَ ۰لْحِجَارَةِ لَمَا يَتَفَجَّرُ مِنْهُ ۴لاَنْهَـٰرُؐ وَإِنَّ مِنْهَا لَمَا يَشَّقَّقُ فَيَخْرُجُ مِنْهُ ۴لْمَآءُؐ وَإِنَّ مِنْهَا لَمَا يَهْبِطُ مِنْ خَشْيَةِ ۱للَّهِؐ وَمَا ۰للَّهُ بِغَـٰفِلٖ عَمَّا تَعْمَلُونَؐ" },
    { ayahId: 81, surahNumber: 2, pageNumber: 11, isComplete: false, continuesFromPrev: false, textData: "أَفَتَطْمَعُونَ أَنْ يُّومِنُواْ لَكُمْ وَقَدْ كَانَ فَرۣيقٌ مِّنْهُمْ يَسْمَعُونَ كَچَمَ ۰للَّهِ ثُمَّ يُحَـرّۣفُونَهُ„ مِنۢ بَعْدِ مَا" }
  ];

